solution:
SELECT c.customer_id, c.name
FROM customers c LEFT JOIN orders o ON c.customer_id = o.customer_id
WHERE o.order_id IS NULL;

SELECT order_id,
  ((EXTRACT(EPOCH FROM (shipped_at - created_at)) / 86400.0) * 86400)/3600 AS hours_to_ship
FROM orders WHERE shipped_at IS NOT NULL;

SELECT customer_id, order_id, order_date
FROM (SELECT *, ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY order_date DESC) rn FROM orders) t
WHERE rn = 1;

SELECT region, SUM(amount) AS region_total,
  100.0 * SUM(amount) / SUM(SUM(amount)) OVER () AS pct_contribution
FROM sales GROUP BY region;

SELECT customer_id,
  CONCAT_WS(', ', street, city, state, zip) AS full_address
FROM customers;

SELECT customer_id, name FROM service_a_customers
UNION
SELECT customer_id, name FROM service_b_customers;

SELECT emp_id, dept_id, salary
FROM employees e
WHERE salary > (SELECT AVG(salary) FROM employees WHERE dept_id = e.dept_id);

SELECT player_id, score,
  (SELECT COUNT(*)+1 FROM scores s2 WHERE s2.score > s1.score) AS rank
FROM scores s1 ORDER BY rank;

SELECT a.customer_id, COUNT(b.order_id) AS related_orders, SUM(b.amount) AS total
FROM orders a JOIN orders b ON a.customer_id = b.customer_id AND a.order_id <> b.order_id
GROUP BY a.customer_id;

SELECT '2024' AS yr, SUM(amount) FROM sales_2024
UNION ALL
SELECT '2025', SUM(amount) FROM sales_2025;

SELECT emp_id, dept_id, salary,
  (SELECT COUNT(*)+1 FROM employees e2 WHERE e2.dept_id = e.dept_id AND e2.salary > e.salary) AS dept_rank
FROM employees e;

SELECT order_date, discount_amount,
  SUM(discount_amount) OVER (ORDER BY order_date) AS cumulative_discount
FROM orders;

SELECT territory, SUM(amount) AS total_sales,
  RANK() OVER (ORDER BY SUM(amount) DESC) AS rk
FROM sales GROUP BY territory;

SELECT AVG(actual_date - scheduled_date) AS avg_delay_days,
  SUM(CASE WHEN actual_date > scheduled_date THEN 1 ELSE 0 END) AS late_count
FROM shipments;

SELECT p.product_id, p.base_price,
  p.base_price * (1 - COALESCE(pr.discount_pct,0)/100.0) AS adjusted_price
FROM products p LEFT JOIN promotions pr ON p.product_id = pr.product_id;

SELECT customer_id, total_spent
FROM (SELECT customer_id, SUM(amount) AS total_spent FROM orders GROUP BY customer_id) t
WHERE total_spent > 1000;

SELECT metric_date, value,
  value - LAG(value) OVER (ORDER BY metric_date) AS day_over_day_change
FROM metrics;

DROP TABLE IF EXISTS active_customers;
DROP TABLE IF EXISTS blacklist;
CREATE TABLE active_customers (id INT);
CREATE TABLE blacklist (id INT);
INSERT INTO active_customers (id) VALUES (1),(2),(3),(4),(5),(6),(7),(8);
INSERT INTO blacklist (id) VALUES (2),(5),(7);
SELECT id FROM active_customers WHERE id NOT IN (SELECT id FROM blacklist);

DROP TABLE IF EXISTS orders;
DROP TABLE IF EXISTS refunds;
CREATE TABLE orders (customer_id INT);
CREATE TABLE refunds (customer_id INT);
INSERT INTO orders (customer_id) VALUES (1),(2),(3),(4),(5),(6),(7),(8);
INSERT INTO refunds (customer_id) VALUES (2),(4),(7),(NULL);
SELECT DISTINCT customer_id FROM orders WHERE customer_id NOT IN (SELECT customer_id FROM refunds WHERE customer_id IS NOT NULL);

SELECT s.name, SUM(sa.amount) AS total
FROM stores s LEFT JOIN sales sa ON s.store_id = sa.store_id
GROUP BY s.name ORDER BY total DESC;

SELECT c.is_loyalty, AVG(o.amount) AS avg_order, COUNT(*) AS n
FROM customers c JOIN orders o ON c.customer_id = o.customer_id
GROUP BY c.is_loyalty;

SELECT AVG(((EXTRACT(EPOCH FROM (processed_at - received_at)) / 86400.0) * 86400)/60) AS avg_minutes_to_process,
  SUM(CASE WHEN processed_at IS NOT NULL THEN 1 ELSE 0 END) AS processed_count
FROM orders;

SELECT warehouse_id,
  100.0 * SUM(CASE WHEN status='fulfilled' THEN 1 ELSE 0 END)/COUNT(*) AS fulfillment_rate
FROM orders GROUP BY warehouse_id;

SELECT region,
  100.0 * (SUM(revenue) - SUM(cost)) / NULLIF(SUM(revenue),0) AS profit_margin_pct
FROM sales GROUP BY region;

SELECT project_id FROM projects
WHERE actual_spend > budget
   OR (deadline ~ '^\d{4}-\d{2}-\d{2}' AND end_date > deadline::date);

SELECT content_id,
  100.0 * NULLIF(regexp_replace(engagements::text, '[^-.0-9]', '', 'g'), '')::numeric / NULLIF(views, 0) AS engagement_rate_pct
FROM content;

SELECT content_id, SUM(play_count) AS plays,
  RANK() OVER (ORDER BY SUM(play_count) DESC) AS popularity_rank
FROM plays GROUP BY content_id;

SELECT user_id, COUNT(*) AS posts,
  MAX(posted_at) AS last_post_at
FROM posts GROUP BY user_id ORDER BY posts DESC;

SELECT order_date, amount,
  SUM(amount) OVER (ORDER BY order_date) AS running_total
FROM orders;

SELECT emp_id,
  100.0 * SUM(CASE WHEN completed::text IN ('1','true','t','TRUE','True') THEN 1 ELSE 0 END)/COUNT(*) AS completion_rate
FROM training GROUP BY emp_id;

SELECT e.emp_id, e.salary, d.dept_name
FROM employees e JOIN departments d ON e.dept_id = d.dept_id
WHERE e.salary > 100;

DROP TABLE IF EXISTS inventory;
CREATE TABLE inventory (
  product_id INT PRIMARY KEY,
  qty_on_hand INT
);
INSERT INTO inventory VALUES
  (1, 50),
  (2, -3),
  (3, 12),
  (4, 0),
  (5, -10),
  (6, 7);

SELECT product_id, qty_on_hand FROM inventory WHERE qty_on_hand < 0;

SELECT region, total FROM (
  SELECT region, SUM(amount) AS total FROM sales GROUP BY region
) s WHERE total > (SELECT AVG(total) FROM (SELECT SUM(amount) AS total FROM sales GROUP BY region) x);

DROP TABLE IF EXISTS projects;
CREATE TABLE projects (project_id INT, start_date DATE, end_date DATE);
INSERT INTO projects (project_id, start_date, end_date) VALUES
  (1, DATE '2024-01-01', DATE '2024-03-31'),
  (2, DATE '2024-02-15', DATE '2024-05-15'),
  (3, DATE '2024-04-01', DATE '2024-06-30'),
  (4, DATE '2024-05-01', DATE '2024-07-31'),
  (5, DATE '2024-08-01', DATE '2024-09-30');
SELECT a.project_id, b.project_id
FROM projects a JOIN projects b
  ON a.project_id < b.project_id
 AND a.start_date < b.end_date AND b.start_date < a.end_date;

SELECT candidate_id, name FROM candidates
WHERE skills_array LIKE '%python%'
  AND skills_array LIKE '%sql%';

SELECT user_id, MAX(posted_at::date) AS last_post,
  CURRENT_DATE - MAX(posted_at::date) AS days_silent
FROM posts GROUP BY user_id HAVING CURRENT_DATE - MAX(posted_at::date) > 30;

SELECT user_id, COUNT(*) AS msgs FROM messages
WHERE sent_at >= '2024-01-01'
GROUP BY user_id ORDER BY msgs DESC LIMIT 10;

SELECT account_id,
  SUM(CASE WHEN txn_type='credit' THEN amount ELSE -amount END) AS balance
FROM transactions GROUP BY account_id;

SELECT issue_month, count,
  count - LAG(count) OVER (ORDER BY issue_month) AS variance_vs_prev_month
FROM cards_issued;

SELECT year, amount,
  100.0 * (amount - LAG(amount) OVER (ORDER BY year)) / NULLIF(LAG(amount) OVER (ORDER BY year),0) AS yoy_pct
FROM revenue;

SELECT step, COUNT(DISTINCT user_id) AS users,
  100.0 * COUNT(DISTINCT user_id) / FIRST_VALUE(COUNT(DISTINCT user_id)) OVER (ORDER BY step) AS pct_of_top
FROM funnel GROUP BY step ORDER BY step;

SELECT stage, COUNT(*) AS apps,
  100.0 * COUNT(*) / SUM(COUNT(*)) OVER () AS pct
FROM applications GROUP BY stage;

SELECT sale_date, amount,
  SUM(amount) OVER (ORDER BY sale_date ROWS UNBOUNDED PRECEDING) AS cumulative
FROM sales;

DROP TABLE IF EXISTS orders_q1;
DROP TABLE IF EXISTS orders_q2;
CREATE TABLE orders_q1 (order_id INT);
CREATE TABLE orders_q2 (order_id INT);
INSERT INTO orders_q1 (order_id) VALUES (1),(2),(3),(4),(5),(6),(7);
INSERT INTO orders_q2 (order_id) VALUES (2),(4),(6),(8),(9);

SELECT order_id FROM orders_q1 EXCEPT SELECT order_id FROM orders_q2;

SELECT user_id, 'active' AS status FROM active_users
UNION
SELECT user_id, 'inactive' FROM inactive_users;

SELECT e.emp_id, COUNT(o.order_id) AS order_count
FROM employees e LEFT JOIN orders o ON e.emp_id = o.emp_id
GROUP BY e.emp_id;

DROP TABLE IF EXISTS instructors;
DROP TABLE IF EXISTS courses;
CREATE TABLE courses (
  course_id INT PRIMARY KEY
);
CREATE TABLE instructors (
  course_id INT
);
INSERT INTO courses VALUES (1), (2), (3), (4), (5);
INSERT INTO instructors VALUES (1), (3), (5);

SELECT c.course_id FROM courses c
LEFT JOIN instructors i ON c.course_id = i.course_id WHERE i.course_id IS NULL;

SELECT c.segment, SUM(o.revenue - o.cost) AS profit
FROM customers c JOIN orders o ON c.customer_id = o.customer_id
GROUP BY c.segment ORDER BY profit DESC;

SELECT customer_id,
  COUNT(*) AS orders, SUM(amount) AS total, AVG(amount) AS avg, MAX(amount) AS max, MIN(amount) AS min
FROM orders GROUP BY customer_id;

WITH dept_avg AS (SELECT dept_id, AVG(salary) AS avg_sal FROM employees GROUP BY dept_id)
SELECT e.emp_id, e.salary, d.avg_sal, e.salary - d.avg_sal AS diff
FROM employees e JOIN dept_avg d ON e.dept_id = d.dept_id;

SELECT AVG(salary) AS median FROM (
  SELECT salary, ROW_NUMBER() OVER (ORDER BY salary) AS rn, COUNT(*) OVER () AS n FROM salaries
) t WHERE rn IN ((n+1)/2, (n+2)/2);

SELECT category, product_id, revenue FROM (
  SELECT *, ROW_NUMBER() OVER (PARTITION BY category ORDER BY revenue DESC) rn FROM sales
) t WHERE rn <= 3;

SELECT emp_id,
  CASE WHEN NULLIF(regexp_replace(performance::text, '[^-.0-9]', '', 'g'), '')::numeric >= 90 AND NULLIF(regexp_replace(tenure_yrs::text, '[^-.0-9]', '', 'g'), '')::numeric >= 2 THEN 'Eligible' ELSE 'Not Eligible' END AS bonus_status
FROM employees;

SELECT 'online' AS channel, SUM(amount) FROM online_sales
UNION ALL
SELECT 'retail', SUM(amount) FROM retail_sales;

DROP TABLE IF EXISTS orders;
CREATE TABLE orders (customer_id INT, product_id INT);
INSERT INTO orders (customer_id, product_id) VALUES
  (1, 100), (1, 200), (1, 300),
  (2, 100), (2, 200),
  (3, 100), (3, 300),
  (4, 200), (4, 300),
  (5, 100), (5, 200),
  (6, 100), (6, 200), (6, 400);
SELECT a.product_id AS p1, b.product_id AS p2, COUNT(*) AS pair_count
FROM orders a JOIN orders b ON a.customer_id = b.customer_id AND a.product_id < b.product_id
GROUP BY a.product_id, b.product_id ORDER BY pair_count DESC LIMIT 10;

SELECT emp_id, period, score,
  AVG(score) OVER (PARTITION BY emp_id ORDER BY period ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) AS rolling3
FROM productivity;

SELECT o.order_id,
  o.original_total - COALESCE(o.discount,0) - COALESCE(r.retro_discount,0) AS final_total
FROM orders o LEFT JOIN retro r ON o.order_id = r.order_id;

SELECT year, amount,
  100.0*(amount-LAG(amount) OVER (ORDER BY year))/NULLIF(LAG(amount) OVER (ORDER BY year),0) AS yoy_pct
FROM revenue;

SELECT movie_id, week, gross,
  gross - LAG(gross) OVER (PARTITION BY movie_id ORDER BY week) AS week_change
FROM box_office;

SELECT customer_id FROM (
  SELECT customer_id, SUM(amount) AS total FROM orders GROUP BY customer_id ORDER BY total DESC LIMIT 10
) t;

SELECT product_id,
  100.0*SUM(CASE WHEN status='cancelled' THEN 1 ELSE 0 END)/COUNT(*) AS cancel_rate
FROM orders GROUP BY product_id HAVING 100.0*SUM(CASE WHEN status='cancelled' THEN 1 ELSE 0 END)/COUNT(*) > 5;

SELECT c.name, SUM(s.amount) AS revenue, c.spend, SUM(s.amount)/NULLIF(c.spend,0) AS roas
FROM campaigns c LEFT JOIN sales s ON c.campaign_id = s.campaign_id
GROUP BY c.name, c.spend;

SELECT AVG(o.amount) AS vip_avg
FROM customers c JOIN orders o ON c.customer_id = o.customer_id
WHERE c.is_vip::int = 1;

SELECT CAST(TO_CHAR(sale_date, 'MM') AS INTEGER) AS mo, SUM(amount) AS total,
  RANK() OVER (ORDER BY SUM(amount) DESC) AS rk
FROM sales GROUP BY CAST(TO_CHAR(sale_date, 'MM') AS INTEGER);

SELECT period, amount,
  AVG(amount) OVER (ORDER BY period ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS rolling_7
FROM profit;

SELECT 100.0 * COUNT(DISTINCT a.user_id) / COUNT(DISTINCT u.user_id) AS activation_rate
FROM users u LEFT JOIN activity a
  ON u.user_id=a.user_id AND a.action_date <= (u.signup_date + INTERVAL '+7 days');

SELECT posted_date, SUM(likes+comments) AS engagement,
  AVG(SUM(likes+comments)) OVER (ORDER BY posted_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS rolling
FROM posts GROUP BY posted_date;

SELECT user_id, song_id, played_at,
  COUNT(*) OVER (PARTITION BY user_id, song_id ORDER BY played_at) AS cumulative_plays
FROM plays;

SELECT * FROM (
  SELECT *, ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY order_date DESC) rn FROM orders
) t WHERE rn=1;

SELECT p.name, SUM(oi.qty) AS units
FROM order_items oi JOIN products p ON oi.product_id = p.product_id
GROUP BY p.name ORDER BY units DESC LIMIT 5;

SELECT product_id, SUM(amount) AS total,
  RANK() OVER (ORDER BY SUM(amount) DESC) AS rk
FROM sales GROUP BY product_id;

SELECT dept_id, AVG(salary) AS dept_avg,
  (SELECT AVG(salary) FROM employees) AS overall_avg
FROM employees GROUP BY dept_id;

SELECT * FROM customers c JOIN
(SELECT customer_id, SUM(amount) AS total FROM orders GROUP BY customer_id) o
ON c.customer_id = o.customer_id;

SELECT e.emp_id, e.name, COUNT(pa.project_id) AS projects
FROM employees e LEFT JOIN project_assignments pa ON e.emp_id = pa.emp_id
GROUP BY e.emp_id, e.name;

DROP TABLE IF EXISTS calendar;
DROP TABLE IF EXISTS events;
CREATE TABLE calendar (d DATE);
CREATE TABLE events (d DATE);
INSERT INTO calendar (d)
SELECT generate_series('2026-05-01'::DATE, '2026-05-10'::DATE, INTERVAL '1 day')::DATE;
INSERT INTO events (d) VALUES
  ('2026-05-01'),('2026-05-02'),('2026-05-05'),('2026-05-08'),('2026-05-10');
SELECT c.d FROM calendar c LEFT JOIN events e ON c.d = e.d WHERE e.d IS NULL;

SELECT c.gender, c.age, SUM(p.amount) AS spend
FROM customers c JOIN purchases p ON c.customer_id = p.customer_id
GROUP BY c.gender, c.age;

SELECT metric_date, value,
  AVG(value) OVER (ORDER BY metric_date ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS ma7
FROM metrics;

DROP TABLE IF EXISTS logs;
CREATE TABLE logs (log_id INT, ids INT);
INSERT INTO logs (log_id, ids) VALUES
  (1, 100),
  (2, 101),
  (3, 102),
  (7, 106),
  (8, 107),
  (12, 110),
  (13, 111),
  (20, 120);

WITH ids AS (SELECT log_id, LAG(log_id) OVER (ORDER BY log_id) AS prev FROM logs)
SELECT prev+1 AS gap_start, log_id-1 AS gap_end FROM ids WHERE log_id - prev > 1;

SELECT course_id, COUNT(*) AS enrolls,
  RANK() OVER (ORDER BY COUNT(*) DESC) AS rk
FROM enrollments GROUP BY course_id;

SELECT i.product_id, NULLIF(regexp_replace(i.qty::text, '[^-.0-9]', '', 'g'), '')::numeric/NULLIF(NULLIF(regexp_replace(s.daily_avg::text, '[^-.0-9]', '', 'g'), '')::numeric, 0) AS days_left
FROM inventory i JOIN sales_velocity s ON i.product_id = s.product_id
WHERE NULLIF(regexp_replace(i.qty::text, '[^-.0-9]', '', 'g'), '')::numeric/NULLIF(NULLIF(regexp_replace(s.daily_avg::text, '[^-.0-9]', '', 'g'), '')::numeric, 0) < 14;

SELECT supplier_id, AVG(days_to_deliver) AS avg_days,
  RANK() OVER (ORDER BY AVG(days_to_deliver)) AS rk
FROM shipments GROUP BY supplier_id;

DROP TABLE IF EXISTS orders;
CREATE TABLE orders (
  order_id INT PRIMARY KEY,
  placed_at TIMESTAMP,
  completed_at TIMESTAMP
);
INSERT INTO orders VALUES
  (1, '2024-05-01 08:00', '2024-05-01 09:30'),
  (2, '2024-05-02 10:00', '2024-05-04 12:00'),
  (3, '2024-05-03 09:00', '2024-05-03 11:00'),
  (4, '2024-05-04 06:00', '2024-05-07 06:00'),
  (5, '2024-05-05 12:00', '2024-05-09 18:00'),
  (6, '2024-05-06 07:00', '2024-05-06 10:00');

SELECT order_id, ((EXTRACT(EPOCH FROM (completed_at - placed_at)) / 86400.0) * 86400)/3600 AS hrs
FROM orders WHERE ((EXTRACT(EPOCH FROM (completed_at - placed_at)) / 86400.0) * 86400)/3600 > 48;

SELECT DATE_TRUNC('month', scheduled_date)::DATE AS mo,
  AVG(actual_date - scheduled_date) AS avg_delay_days
FROM shipments GROUP BY DATE_TRUNC('month', scheduled_date)::DATE;

SELECT week_start, visits,
  100.0*(NULLIF(regexp_replace(visits::text, '[^-.0-9]', '', 'g'), '')::numeric - LAG(NULLIF(regexp_replace(visits::text, '[^-.0-9]', '', 'g'), '')::numeric) OVER (ORDER BY week_start))/NULLIF(LAG(NULLIF(regexp_replace(visits::text, '[^-.0-9]', '', 'g'), '')::numeric) OVER (ORDER BY week_start), 0) AS wow_pct
FROM traffic;

DROP TABLE IF EXISTS invoices;
CREATE TABLE invoices (invoice_id INT, due_date DATE, paid_date DATE);
INSERT INTO invoices (invoice_id, due_date, paid_date) VALUES
  (1, DATE '2025-01-15', DATE '2025-01-10'),
  (2, DATE '2025-01-20', DATE '2025-02-05'),
  (3, DATE '2025-02-01', DATE '2025-02-10'),
  (4, DATE '2025-02-15', DATE '2025-02-15'),
  (5, DATE '2025-03-01', DATE '2025-03-20'),
  (6, DATE '2025-03-10', DATE '2025-03-12');
SELECT invoice_id, paid_date - due_date AS days_late
FROM invoices WHERE paid_date > due_date;

SELECT period, new_subs - cancelled_subs AS net,
  SUM(new_subs - cancelled_subs) OVER (ORDER BY period) AS cumulative_subs
FROM subscriptions;

SELECT route, AVG(delay_minutes) AS avg_delay,
  SUM(CASE WHEN delay_minutes > 30 THEN 1 ELSE 0 END) AS late_flights
FROM flights GROUP BY route;

SELECT a.book_id AS b1, b.book_id AS b2, COUNT(*) AS pair_count
FROM downloads a JOIN downloads b ON a.user_id = b.user_id AND a.book_id < b.book_id
GROUP BY a.book_id, b.book_id;

SELECT month, members,
  100.0*(NULLIF(regexp_replace(members::text, '[^-.0-9]', '', 'g'), '')::numeric - LAG(NULLIF(regexp_replace(members::text, '[^-.0-9]', '', 'g'), '')::numeric) OVER (ORDER BY month))/NULLIF(LAG(NULLIF(regexp_replace(members::text, '[^-.0-9]', '', 'g'), '')::numeric) OVER (ORDER BY month), 0) AS mom_growth
FROM network;

SELECT product_id, profit_margin,
  DENSE_RANK() OVER (ORDER BY profit_margin DESC) AS rk
FROM products;

SELECT supplier_id, AVG(CASE WHEN on_time IS NOT NULL THEN 1.0 ELSE 0 END) AS rate,
  RANK() OVER (ORDER BY AVG(CASE WHEN on_time IS NOT NULL THEN 1.0 ELSE 0 END) DESC) AS rk
FROM shipments GROUP BY supplier_id;

SELECT customer_id, order_date,
  order_date - LAG(order_date) OVER (PARTITION BY customer_id ORDER BY order_date) AS gap_days
FROM orders;

SELECT c.campaign_id, c.spend / NULLIF(COUNT(DISTINCT cv.customer_id),0) AS cpa
FROM campaigns c LEFT JOIN conversions cv ON c.campaign_id = cv.campaign_id
GROUP BY c.campaign_id, c.spend;

SELECT product_id, name, price,
  ROW_NUMBER() OVER (ORDER BY price ASC) AS price_rank
FROM products;

SELECT rep_id, SUM(amount) AS total,
  DENSE_RANK() OVER (ORDER BY SUM(amount) DESC) AS rk
FROM sales GROUP BY rep_id;

SELECT warehouse_id, capacity, used, NULLIF(regexp_replace(capacity::text, '[^-.0-9]', '', 'g'), '')::numeric - NULLIF(regexp_replace(used::text, '[^-.0-9]', '', 'g'), '')::numeric AS available,
  100.0*NULLIF(regexp_replace(used::text, '[^-.0-9]', '', 'g'), '')::numeric/NULLIF(NULLIF(regexp_replace(capacity::text, '[^-.0-9]', '', 'g'), '')::numeric, 0) AS utilization_pct
FROM warehouses WHERE 100.0*NULLIF(regexp_replace(used::text, '[^-.0-9]', '', 'g'), '')::numeric/NULLIF(NULLIF(regexp_replace(capacity::text, '[^-.0-9]', '', 'g'), '')::numeric, 0) > 80;

DROP TABLE IF EXISTS ads;
CREATE TABLE ads (ad_id INT, status TEXT, last_active_date DATE);
INSERT INTO ads (ad_id, status, last_active_date) VALUES
  (1,'active', CURRENT_DATE - INTERVAL '5 days'),
  (2,'active', CURRENT_DATE - INTERVAL '45 days'),
  (3,'active', CURRENT_DATE - INTERVAL '60 days'),
  (4,'inactive', CURRENT_DATE - INTERVAL '120 days'),
  (5,'active', CURRENT_DATE - INTERVAL '15 days'),
  (6,'active', CURRENT_DATE - INTERVAL '90 days');
UPDATE ads SET status='inactive'
WHERE last_active_date < CURRENT_DATE - INTERVAL '30 days' AND status='active';
SELECT ad_id, status, last_active_date FROM ads ORDER BY ad_id;

SELECT a.topping AS t1, b.topping AS t2, c.topping AS t3
FROM toppings a JOIN toppings b ON a.topping < b.topping
JOIN toppings c ON b.topping < c.topping;

SELECT DISTINCT a.caller_id FROM calls a JOIN calls b
ON a.caller_id = b.caller_id AND a.call_at < b.call_at
AND b.call_at <= a.call_at + INTERVAL '7 days';

SELECT server_id,
  100.0 * SUM(CASE WHEN status='up' THEN 1 ELSE 0 END)/COUNT(*) AS uptime_pct
FROM server_status GROUP BY server_id;

DROP TABLE IF EXISTS orders_jan;
DROP TABLE IF EXISTS orders_feb;
