def diameterOfBinaryTree(root):
    best = 0
    def depth(n):
        nonlocal best
        if not n: return 0
        l, r = depth(n.left), depth(n.right)
        best = max(best, l+r)
        return 1 + max(l, r)
    depth(root)
    return best

def isBalanced(root):
    def h(n):
        if not n: return 0
        l, r = h(n.left), h(n.right)
        if l < 0 or r < 0 or abs(l-r) > 1: return -1
        return 1 + max(l, r)
    return h(root) >= 0

def isSameTree(p, q):
