def networkDelayTime(times, n, k):
    g = defaultdict(list)
    for u, v, w in times: g[u].append((v, w))
    dist = {}; pq = [(0, k)]
    while pq:
        d, u = heapq.heappop(pq)
        if u in dist: continue
        dist[u] = d
        for v, w in g[u]:
            if v not in dist: heapq.heappush(pq, (d+w, v))
    return max(dist.values()) if len(dist) == n else -1

