def largestRectangleArea(h):
    st, best = [], 0   # stack of (start_index, height)
    for i, x in enumerate(h):
        start = i
        while st and st[-1][1] > x:
            j, y = st.pop()
            best = max(best, y * (i - j))
            start = j
        st.append((start, x))
    for j, y in st:
        best = max(best, y * (len(h) - j))
    return best

