def levelOrder(root):
    if not root: return []
    q, res = deque([root]), []
    while q:
        level = []
        for _ in range(len(q)):
            n = q.popleft(); level.append(n.val)
            if n.left:  q.append(n.left)
            if n.right: q.append(n.right)
        res.append(level)
    return res

from collections import deque

def rightSideView(root):
    if not root: return []
    q, res = deque([root]), []
    while q:
        sz = len(q)
        for i in range(sz):
            n = q.popleft()
            if i == sz - 1: res.append(n.val)
            if n.left:  q.append(n.left)
            if n.right: q.append(n.right)
    return res

def goodNodes(root):
    def dfs(n, max_so_far):
        if not n: return 0
        good = 1 if n.val >= max_so_far else 0
        m = max(max_so_far, n.val)
        return good + dfs(n.left, m) + dfs(n.right, m)
    return dfs(root, root.val if root else 0)

