def buildTree(preorder, inorder):
    inorder_idx = {v: i for i, v in enumerate(inorder)}
    pre_iter = iter(preorder)
    def helper(lo, hi):
        if lo > hi: return None
        val = next(pre_iter); idx = inorder_idx[val]
        node = TreeNode(val)
        node.left  = helper(lo, idx - 1)
        node.right = helper(idx + 1, hi)
        return node
    return helper(0, len(inorder) - 1)

def maxPathSum(root):
    best = float('-inf')
    def gain(n):
        nonlocal best
        if not n: return 0
        l = max(0, gain(n.left))
        r = max(0, gain(n.right))
        best = max(best, n.val + l + r)
        return n.val + max(l, r)
    gain(root); return best

def findWords(board, words):
    # Build trie
    root = {}
    for w in words:
        n = root
        for c in w: n = n.setdefault(c, {})
        n['#'] = w
    R, C = len(board), len(board[0])
    found = set()
    def dfs(r, c, n):
        ch = board[r][c]
        if ch not in n: return
        n = n[ch]
        if '#' in n: found.add(n['#'])
        board[r][c] = '*'
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < R and 0 <= nc < C: dfs(nr, nc, n)
        board[r][c] = ch
    for r in range(R):
        for c in range(C): dfs(r, c, root)
    return list(found)

