from collections import defaultdict, deque

def canFinish(n, prereq):
    g = defaultdict(list); deg = [0] * n
    for a, b in prereq: g[b].append(a); deg[a] += 1
    q = deque([i for i in range(n) if deg[i] == 0]); done = 0
    while q:
        x = q.popleft(); done += 1
        for y in g[x]:
            deg[y] -= 1
            if deg[y] == 0: q.append(y)
    return done == n

from collections import defaultdict, deque

def findOrder(n, prereq):
    g = defaultdict(list); deg = [0] * n
    for a, b in prereq: g[b].append(a); deg[a] += 1
    q = deque([i for i in range(n) if deg[i] == 0]); order = []
    while q:
        x = q.popleft(); order.append(x)
        for y in g[x]:
            deg[y] -= 1
            if deg[y] == 0: q.append(y)
    return order if len(order) == n else []

def findRedundantConnection(edges):
    parent = list(range(len(edges) + 1))
    def find(x):
        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x
    for a, b in edges:
        ra, rb = find(a), find(b)
        if ra == rb: return [a, b]
        parent[ra] = rb

def countComponents(n, edges):
    parent = list(range(n))
    def find(x):
        while parent[x] != x: parent[x] = parent[parent[x]]; x = parent[x]
        return x
    for a, b in edges:
        ra, rb = find(a), find(b)
        if ra != rb: parent[ra] = rb
    return len({find(i) for i in range(n)})

from collections import defaultdict, deque

def ladderLength(beginWord, endWord, wordList):
    if endWord not in wordList: return 0
    L = len(beginWord)
    patterns = defaultdict(list)
    for w in wordList:
        for i in range(L):
            patterns[w[:i] + '*' + w[i+1:]].append(w)
    seen = {beginWord}
    q = deque([(beginWord, 1)])
    while q:
        w, d = q.popleft()
        if w == endWord: return d
        for i in range(L):
            for nxt in patterns[w[:i] + '*' + w[i+1:]]:
                if nxt not in seen:
                    seen.add(nxt); q.append((nxt, d + 1))
    return 0

