def findItinerary(tickets):
    g = defaultdict(list)
    for a, b in sorted(tickets): heapq.heappush(g[a], b)
    route = []
    def dfs(u):
        while g[u]: dfs(heapq.heappop(g[u]))
        route.append(u)
    dfs('JFK'); return route[::-1]

import heapq

def minCostConnectPoints(points):
    n = len(points); seen = {0}; total = 0
    h = [(abs(points[0][0] - points[j][0]) + abs(points[0][1] - points[j][1]), j) for j in range(1, n)]
    heapq.heapify(h)
    while len(seen) < n:
        d, u = heapq.heappop(h)
        if u in seen: continue
        seen.add(u); total += d
        for v in range(n):
            if v not in seen:
                heapq.heappush(h, (abs(points[u][0]-points[v][0]) + abs(points[u][1]-points[v][1]), v))
    return total

