from collections import defaultdict, deque

def alienOrder(words):
    deg = {c: 0 for w in words for c in w}
    g = defaultdict(set)
    for a, b in zip(words, words[1:]):
        if len(a) > len(b) and a.startswith(b): return ""
        for x, y in zip(a, b):
            if x != y:
                if y not in g[x]:
                    g[x].add(y)
                    deg[y] += 1
                break
    q = deque([c for c in deg if deg[c] == 0])
    order = []
    while q:
        c = q.popleft(); order.append(c)
        for nxt in g[c]:
            deg[nxt] -= 1
            if deg[nxt] == 0: q.append(nxt)
    return ''.join(order) if len(order) == len(deg) else ""

from collections import defaultdict, deque

def findCheapestPrice(n, flights, src, dst, k):
    g = defaultdict(list)
    for u, v, w in flights: g[u].append((v, w))
    INF = float('inf'); cost = [INF] * n; cost[src] = 0
    q = deque([(src, 0, 0)])
    while q:
        u, c, stops = q.popleft()
        if stops > k: continue
        for v, w in g[u]:
            if c + w < cost[v]:
                cost[v] = c + w; q.append((v, c + w, stops + 1))
    return -1 if cost[dst] == INF else cost[dst]

def canJump(nums):
    reach = 0
    for i, n in enumerate(nums):
        if i > reach: return False
        reach = max(reach, i + n)
    return True

def jump(nums):
    jumps = end = far = 0
    for i in range(len(nums) - 1):
        far = max(far, i + nums[i])
        if i == end: jumps += 1; end = far
    return jumps

def mergeTriplets(triplets, target):
    have = [False] * 3
    for t in triplets:
        if all(t[i] <= target[i] for i in range(3)):
            for i in range(3):
                if t[i] == target[i]: have[i] = True
    return all(have)

def partitionLabels(s):
    last = {c: i for i, c in enumerate(s)}
    res, start, end = [], 0, 0
    for i, c in enumerate(s):
        end = max(end, last[c])
        if i == end: res.append(end - start + 1); start = i + 1
    return res

import heapq

def minMeetingRooms(intervals):
    intervals.sort(key=lambda x: x[0])
    h = []
    for s, e in intervals:
        if h and h[0] <= s: heapq.heappop(h)
        heapq.heappush(h, e)
    return len(h)

import heapq

def minInterval(intervals, queries):
    intervals.sort()
    sorted_q = sorted(set(queries))
    res = {}; h = []; i = 0
    for q in sorted_q:
        while i < len(intervals) and intervals[i][0] <= q:
            l, r = intervals[i]
            heapq.heappush(h, (r - l + 1, r)); i += 1
        while h and h[0][1] < q: heapq.heappop(h)
        res[q] = h[0][0] if h else -1
    return [res[q] for q in queries]

