import os, urllib.request, hashlib
from concurrent.futures import ThreadPoolExecutor, as_completed
from pathlib import Path

OUT = Path('./downloads')
OUT.mkdir(exist_ok=True)

def local_path(url):
    # Stable filename from URL hash to avoid collisions / weird chars
    h = hashlib.sha1(url.encode()).hexdigest()[:12]
    ext = os.path.splitext(url.split('?')[0])[1] or '.bin'
    return OUT / f"{h}{ext}"

def download(url):
    dst = local_path(url)
    if dst.exists() and dst.stat().st_size > 0:
        return (url, 'skipped')
    try:
        urllib.request.urlretrieve(url, dst)
        return (url, 'ok')
    except Exception as e:
        if dst.exists(): dst.unlink()      # remove partial
        return (url, f'error: {e}')

urls = [line.strip() for line in open('urls.txt') if line.strip()]
with ThreadPoolExecutor(max_workers=8) as ex:
    futures = [ex.submit(download, u) for u in urls]
    for f in as_completed(futures):
        url, status = f.result()
        print(f"{status:8s} {url}")

