import hashlib
from pathlib import Path
from collections import defaultdict

def file_hash(path, chunk=1 << 20):           # 1 MiB chunks
    h = hashlib.sha256()
    with open(path, 'rb') as f:
        while True:
            data = f.read(chunk)
            if not data: break
            h.update(data)
    return h.hexdigest()

groups = defaultdict(list)
for p in Path('/photos').rglob('*'):
    if p.is_file():
        groups[file_hash(p)].append(p)

for digest, paths in groups.items():
    if len(paths) > 1:
        print(f"\n{digest[:12]}  ({len(paths)} copies)")
        for p in paths:
            print(f"  {p}")

# Optimization for huge libraries: bucket by file SIZE first; only hash
# files whose sizes collide. Most files have unique sizes, so you skip
