import os, re, time

PATTERN = re.compile(r'ERROR|FATAL|Traceback')

def tail(path, poll=0.5):
    f = open(path)
    f.seek(0, 2)                              # jump to end of file
    inode = os.fstat(f.fileno()).st_ino
    while True:
        line = f.readline()
        if line:
            if PATTERN.search(line):
                yield line.rstrip()
            continue
        time.sleep(poll)
        # Detect rotation: the file at this path now has a different inode
        try:
            new_inode = os.stat(path).st_ino
        except FileNotFoundError:
            continue
        if new_inode != inode:
            f.close()
            f = open(path)
            inode = new_inode
            print('--- log rotated, reopened ---')

if __name__ == '__main__':
    for hit in tail('/var/log/app.log'):
        print(hit)

